import { revalidateTag } from 'next/cache';
import { getCachedProducts } from '@/lib/products';
import { syncCatalogFromUpstream } from '@/lib/db';

/* ──────────── Inline Server Action ──────────── */

/**
 * Triggers a full catalog sync from the upstream ERP/PIM system
 * and invalidates all cached data tagged with `"products"`.
 *
 * The action returns as soon as the sync completes so the page
 * re-renders with fresh data.  In production the actual sync would
 * be an enqueued background job — the cache invalidation is the
 * critical part that unblocks downstream views.
 */
async function syncCatalog() {
  'use server';

  // 1. Pull latest pricing / inventory / availability from upstream.
  const { syncedAt, count } = await syncCatalogFromUpstream();

  // 2. Purge every cache entry tagged "products" so the NEXT render
  //    fetches fresh data from wherever it reads the catalog.
  revalidateTag('products');

  console.log(`[Sync] ${count} products synced at ${syncedAt}`);
}

/* ──────────── Page Component ──────────── */

export default async function AdminCatalogPage() {
  const products = await getCachedProducts();

  return (
    <div style={pageStyle}>
      <header style={headerStyle}>
        <h1 style={headingStyle}>Product Catalog</h1>
        <p style={subtitleStyle}>
          Admin view &middot; data cached with tag <code>&quot;products&quot;</code>
        </p>
      </header>

      <form action={syncCatalog} style={formStyle}>
        <button type="submit" style={buttonStyle}>
          &#x21bb; Sync Latest Catalog
        </button>
        <span style={hintStyle}>
          Syncs pricing, inventory and availability from the upstream system.
          Cached data is invalidated so catalog views refresh on next load.
        </span>
      </form>

      {products.length === 0 ? (
        <p style={emptyStyle}>No products found in the catalog.</p>
      ) : (
        <table style={tableStyle}>
          <thead>
            <tr>
              <th style={thStyle}>ID</th>
              <th style={thStyle}>Name</th>
              <th style={thStyle}>Price</th>
              <th style={thStyle}>Stock</th>
              <th style={thStyle}>Status</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr key={product.id}>
                <td style={tdStyle}>{product.id}</td>
                <td style={tdBoldStyle}>{product.name}</td>
                <td style={tdStyle}>${product.price.toFixed(2)}</td>
                <td style={tdStyle}>{product.stock}</td>
                <td style={tdStyle}>
                  <span
                    style={{
                      ...badgeStyle,
                      backgroundColor:
                        product.status === 'active'
                          ? 'var(--green, #16a34a)'
                          : 'var(--amber, #d97706)',
                    }}
                  >
                    {product.status}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}

      <p style={footerStyle}>
        <strong>How it works:</strong> The product list is served from a
        shared cache tagged <code>&quot;products&quot;</code>.  Clicking the
        sync button runs the Server Action above, which syncs from upstream
        and then calls <code>revalidateTag(&quot;products&quot;)</code>.
        Every page or widget that depends on the same cache tag picks up the
        fresh data on its next render — no per-request database queries.
      </p>
    </div>
  );
}

/* ──────────── Inline Styles ──────────── */

